import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"功能总览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/frontend-home.md","filePath":"guide/features/frontend-home.md","lastUpdated":1780491682000}'),h={name:"guide/features/frontend-home.md"};function o(l,t,i,n,s,b){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="功能总览" tabindex="-1">功能总览 <a class="header-anchor" href="#功能总览" aria-label="Permalink to &quot;功能总览&quot;">​</a></h1><p>功能菜单按使用场景分成三类：系统配置、资源获取、资源整理。第一次使用时，不建议同时打开所有功能，可以先验证一个常用流程，再逐步扩展。</p><h2 id="首页" tabindex="-1">首页 <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页&quot;">​</a></h2><p>首页展示当前服务概况、任务指标、常用入口和授权状态。它适合用来快速判断：</p><ul><li>服务是否正常运行</li><li>最近任务是否有异常</li><li>授权是否有效</li><li>常用功能是否需要处理</li></ul><h2 id="系统日志" tabindex="-1">系统日志 <a class="header-anchor" href="#系统日志" aria-label="Permalink to &quot;系统日志&quot;">​</a></h2><p>系统日志用于排查问题。页面只展示最新窗口，完整日志可以下载 <code>data/log/app.log</code>。</p><p>遇到“没有搜索结果”“转存失败”“通知没有发出”这类问题时，先看系统日志，再去对应配置页检查账号、目录和网络。</p><h2 id="系统配置" tabindex="-1">系统配置 <a class="header-anchor" href="#系统配置" aria-label="Permalink to &quot;系统配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>菜单</th><th>用途</th></tr></thead><tbody><tr><td>网盘配置</td><td>添加 123 云盘、115 网盘账号。</td></tr><tr><td>代理配置</td><td>只影响 Telegram 和 TMDB 请求。</td></tr><tr><td>Telegram 配置</td><td>登录 Telegram、维护内置机器人和频道资源池。</td></tr><tr><td>邮箱配置</td><td>发送系统通知、管理员邮件和豆瓣求片用户邮件。</td></tr><tr><td>媒体服务配置</td><td>配置 TMDB 和 Emby。</td></tr></tbody></table><p>详细说明见 <a href="/guide/help/system-settings">系统配置</a>。</p><h2 id="资源获取" tabindex="-1">资源获取 <a class="header-anchor" href="#资源获取" aria-label="Permalink to &quot;资源获取&quot;">​</a></h2><table tabindex="0"><thead><tr><th>菜单</th><th>适合做什么</th></tr></thead><tbody><tr><td>转存策略</td><td>给网盘设置可用转存目录，指定整理源目录，配置机器人转存。</td></tr><tr><td>监控策略</td><td>决定自动监控的刷新频率、搜索来源和转存目标。</td></tr><tr><td>频道扫描</td><td>扫描频道历史消息，发现分享链接后手动执行转存。</td></tr><tr><td>频道监控</td><td>让某些频道的新消息持续进入监控流程。</td></tr><tr><td>TMDB 看板</td><td>浏览或搜索电影、剧集，并手动加入监控。</td></tr><tr><td>榜单订阅</td><td>订阅猫眼、豆瓣、TMDB 榜单，把榜单条目加入监控。</td></tr><tr><td>豆瓣求片</td><td>读取用户豆瓣片单，自动处理想看的电影和剧集。</td></tr><tr><td>监控清单</td><td>查看当前所有监控条目的状态、缺集情况和处理历史。</td></tr></tbody></table><p>详细说明见 <a href="/guide/help/resource-acquisition">资源获取</a> 和 <a href="/guide/help/douban-requests">豆瓣求片</a>。</p><h2 id="资源整理" tabindex="-1">资源整理 <a class="header-anchor" href="#资源整理" aria-label="Permalink to &quot;资源整理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>菜单</th><th>用途</th></tr></thead><tbody><tr><td>Emby 缺集扫描</td><td>扫描媒体库里已入库但缺集的剧集，并把缺集条目加入监控。</td></tr></tbody></table><p>详细说明见 <a href="/guide/help/emby-missing">Emby 缺集扫描</a>。</p><h2 id="功能依赖" tabindex="-1">功能依赖 <a class="header-anchor" href="#功能依赖" aria-label="Permalink to &quot;功能依赖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>至少需要先配置</th></tr></thead><tbody><tr><td>频道扫描</td><td>网盘账号、转存策略、Telegram 频道或公开频道。</td></tr><tr><td>监控策略 / 榜单订阅 / TMDB 看板</td><td>TMDB、Emby、搜索来源、转存目标。</td></tr><tr><td>豆瓣求片</td><td>Emby、TMDB、监控策略里的搜索来源。</td></tr><tr><td>Emby 缺集扫描</td><td>Emby 配置。</td></tr><tr><td>邮件通知</td><td>邮箱配置。</td></tr></tbody></table><p>如果某个页面提示依赖未配置，先回到对应配置页补齐，不要绕开页面强行调整状态。</p>',20)])])}const p=d(h,[["render",o]]);export{m as __pageData,p as default};
